14	#[actix_web::main]
15	async fn main() -> std::io::Result<()> {
16	    dotenv().ok();
17	
18	    let cfg = config::Config::from_env();
19	
20	    env_logger::Builder::from_env(
21	        env_logger::Env::default().default_filter_or(&cfg.log_level),
22	    )
23	    .init();
24	
25	    info!("Meridian backend starting on {}:{}", cfg.host, cfg.port);
26	
27	    let pool = db::create_pool(&cfg.database_url)
28	        .await
29	        .expect("Failed to create database pool");
30	
31	    info!("Database pool created");
32	
33	    // Run migrations on startup
34	    db::run_migrations(&pool)
35	        .await
36	        .expect("Failed to run database migrations");
37	
38	    info!("Migrations applied successfully");
39	
40	    let pool = web::Data::new(pool);
41	    let bind_addr = format!("{}:{}", cfg.host, cfg.port);
42	
43	    info!("Starting HTTP server at http://{}", bind_addr);
44	
45	    HttpServer::new(move || {
46	        let cors = Cors::default()
47	            .allowed_origin("http://localhost:8081")
48	            .allowed_origin("http://127.0.0.1:8081")
49	            .allow_any_method()
50	            .allow_any_header()
51	            .supports_credentials()
52	            .max_age(3600);
53	
54	        App::new()
55	            .app_data(pool.clone())
56	            .wrap(cors)
57	            .wrap(Logger::default())
58	            .configure(routes::configure_routes)
59	    })
60	    .bind(&bind_addr)?
61	    .run()
62	    .await
63	}
