16	fn switch(route: Route) -> Html {
17	    match route {
18	        Route::Login => html! { <LoginPage /> },
19	        Route::Unauthorized => html! { <UnauthorizedPage /> },
20	        Route::Admin | Route::AdminUsers | Route::AdminDeletionRequests => {
21	            html! {
22	                <QuickLock>
23	                    <RoleGuard required_role="Administrator"><AdminShell /></RoleGuard>
24	                </QuickLock>
25	            }
26	        }
27	        Route::TeacherClasses => {
28	            html! { <RoleGuard required_role="Teacher"><TeacherClassesShell /></RoleGuard> }
29	        }
30	        // Check-in pages manage their own auth/role guards internally.
31	        Route::Checkin => html! { <CheckinPage /> },
32	        Route::CheckinReview => html! {
33	            <QuickLock>
34	                <CheckinReviewPage />
35	            </QuickLock>
36	        },
37	        Route::Inbox => html! { <InboxPage /> },
38	        Route::Preferences => html! { <PreferencesPage /> },
39	        Route::Home | Route::NotFound => html! { <AuthGuard /> },
40	    }
41	}
