43	#[function_component(AuthGuard)]
44	fn auth_guard() -> Html {
45	    let state = use_context::<AppStateContext>().expect("AppState context not found");
46	    let navigator = use_navigator().unwrap();
47	    let authenticated = state.is_authenticated();
48	
49	    // Hooks must be called unconditionally — redirect happens inside the effect
50	    {
51	        let navigator = navigator.clone();
52	        use_effect_with(authenticated, move |&auth| {
53	            if !auth {
54	                navigator.push(&Route::Login);
55	            }
56	        });
57	    }
58	
59	    if authenticated {
60	        html! { <HomePage /> }
61	    } else {
62	        html! { <div class="loading">{ "Redirecting\u{2026}" }</div> }
63	    }
64	}
