66	#[derive(Properties, PartialEq)]
67	pub struct RoleGuardProps {
68	    pub required_role: &'static str,
69	    pub children: Children,
70	}
71	
72	#[function_component(RoleGuard)]
73	fn role_guard(props: &RoleGuardProps) -> Html {
74	    let state = use_context::<AppStateContext>().expect("AppState context not found");
75	    let navigator = use_navigator().unwrap();
76	    let authenticated = state.is_authenticated();
77	    let has_role = state.has_role(props.required_role);
78	
79	    let role = props.required_role;
80	    use_effect_with((authenticated, has_role), move |(auth, role_ok)| {
81	        if !auth {
82	            navigator.push(&Route::Login);
83	        } else if !role_ok {
84	            navigator.push(&Route::Unauthorized);
85	        }
86	        let _ = role; // suppress unused warning
87	    });
88	
89	    if authenticated && has_role {
90	        html! { for props.children.iter() }
91	    } else if authenticated && !has_role {
92	        html! { <UnauthorizedPage /> }
93	    } else {
94	        html! { <div class="loading">{ "Checking access\u{2026}" }</div> }
95	    }
96	}
