118	#[function_component(App)]
119	pub fn app() -> Html {
120	    let app_state = use_state(AppState::default);
121	    // Global lock state — false = unlocked, true = locked.
122	    // Provided at root so it persists across route changes.
123	    let lock_state = use_state(|| false);
124	
125	    // On mount, if we have a stored token, validate it by fetching the current user.
126	    {
127	        let app_state = app_state.clone();
128	        use_effect_with((), move |_| {
129	            let app_state = app_state.clone();
130	            if let Some(token) = (*app_state).token.clone() {
131	                wasm_bindgen_futures::spawn_local(async move {
132	                    match auth::me(&token).await {
133	                        Ok(user) => {
134	                            let mut new_state = (*app_state).clone();
135	                            new_state.user = Some(user);
136	                            app_state.set(new_state);
137	                        }
138	                        Err(_) => {
139	                            // Token is invalid or expired — clear it.
140	                            let mut new_state = (*app_state).clone();
141	                            new_state.logout();
142	                            app_state.set(new_state);
143	                        }
144	                    }
145	                });
146	            }
147	        });
148	    }
149	
150	    let on_logout = {
151	        let app_state = app_state.clone();
152	        let lock_state = lock_state.clone();
153	        Callback::from(move |_: ()| {
154	            let token = (*app_state).token.clone();
155	            let app_state = app_state.clone();
156	            let lock_state = lock_state.clone();
157	            wasm_bindgen_futures::spawn_local(async move {
158	                if let Some(t) = token {
159	                    let _ = auth::logout(&t).await;
160	                }
161	                let mut new_state = (*app_state).clone();
162	                new_state.logout();
163	                app_state.set(new_state);
164	                // Clear lock state on logout so the next user starts fresh.
165	                lock_state.set(false);
166	            });
167	        })
168	    };
169	
170	    html! {
171	        <ContextProvider<AppStateContext> context={app_state.clone()}>
172	            <ContextProvider<LockContext> context={lock_state.clone()}>
173	                <BrowserRouter>
174	                    <div id="app">
175	                        <Layout on_logout={on_logout}>
176	                            <Switch<Route> render={switch} />
177	                        </Layout>
178	                    </div>
179	                </BrowserRouter>
