4	pub const API_BASE: &str = "http://localhost:8080/api/v1";
5	
6	#[derive(Debug)]
7	pub enum ApiError {
8	    Network(String),
9	    Deserialize(String),
10	    Http { status: u16, message: String },
11	}
12	
13	impl std::fmt::Display for ApiError {
14	    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
15	        match self {
16	            ApiError::Network(e) => write!(f, "Network error: {}", e),
17	            ApiError::Deserialize(e) => write!(f, "Parse error: {}", e),
18	            ApiError::Http { status, message } => write!(f, "HTTP {}: {}", status, message),
19	        }
20	    }
21	}
22	
23	pub async fn get<T: DeserializeOwned>(path: &str, token: Option<&str>) -> Result<T, ApiError> {
24	    let url = format!("{}{}", API_BASE, path);
25	    let mut req = Request::get(&url);
26	    if let Some(t) = token {
27	        req = req.header("Authorization", &format!("Bearer {}", t));
28	    }
29	    let resp = req
30	        .send()
31	        .await
32	        .map_err(|e| ApiError::Network(e.to_string()))?;
33	    if resp.status() >= 400 {
34	        let msg = resp.text().await.unwrap_or_default();
35	        return Err(ApiError::Http {
36	            status: resp.status(),
37	            message: msg,
38	        });
39	    }
40	    resp.json::<T>()
41	        .await
42	        .map_err(|e| ApiError::Deserialize(e.to_string()))
43	}
