///
/// Runs in a dedicated tokio task spawned from `main()`.  On each tick
/// (every 60 seconds) it:
///
/// 1. Finds all orders with status = 'pending' created more than 30 minutes
///    ago.
/// 2. Updates them to status = 'cancelled'.
/// 3. Creates an 'order' inbox notification for each affected customer.
/// 4. Writes an audit log entry.

use uuid::Uuid;

use crate::db::DbPool;

/// How often the scheduler runs (seconds).
const TICK_INTERVAL_SECS: u64 = 60;

/// How long before a pending order is auto-cancelled (seconds).
const ORDER_EXPIRY_SECS: i64 = 30 * 60; // 30 minutes

pub async fn run_scheduler(pool: DbPool) {
    log::info!(
        "Scheduler started: auto-close interval={}s, order_expiry={}s",
        TICK_INTERVAL_SECS,
        ORDER_EXPIRY_SECS
    );

    loop {
        tokio::time::sleep(tokio::time::Duration::from_secs(TICK_INTERVAL_SECS)).await;
