/// Cancel all pending orders that are older than ORDER_EXPIRY_SECS.
///
/// Returns the number of orders closed.
pub async fn auto_close_expired_orders(pool: &DbPool) -> Result<usize, sqlx::Error> {
    // Find expired pending orders.
    let rows: Vec<(Uuid, Uuid)> = sqlx::query_as(
        "SELECT id, user_id FROM orders
         WHERE status = 'pending'
           AND created_at < NOW() - make_interval(secs => $1::double precision)
         FOR UPDATE SKIP LOCKED",
    )
    .bind(ORDER_EXPIRY_SECS as f64)
    .fetch_all(pool)
    .await?;

    if rows.is_empty() {
        return Ok(0);
    }

    let order_ids: Vec<Uuid> = rows.iter().map(|(id, _)| *id).collect();

    // Bulk-cancel.
    sqlx::query(
        "UPDATE orders
         SET status = 'cancelled', updated_at = NOW()
         WHERE id = ANY($1)",
    )
    .bind(&order_ids)
    .execute(pool)
    .await?;

    log::info!(
        "Scheduler: auto-cancelled {} expired pending orders: {:?}",
        order_ids.len(),
        order_ids
    );

    // Notify each customer and write an audit log entry.
    for (order_id, user_id) in &rows {
        // Customer notification (fire-and-forget; ignore individual errors).
        let _ = sqlx::query(
            "INSERT INTO notifications
                 (id, recipient_id, subject, body, notification_type, created_at)
             VALUES ($1, $2, $3, $4, 'order', NOW())",
        )
        .bind(Uuid::new_v4())
        .bind(user_id)
        .bind("Order auto-cancelled")
        .bind(format!(
            "Your order {} was automatically cancelled because payment was not completed within 30 minutes.",
            order_id
        ))
        .execute(pool)
        .await;

        // Audit log.
        let _ = sqlx::query(
            "INSERT INTO audit_logs
                 (id, actor_id, action, entity_type, entity_id, old_data, new_data, created_at)
             VALUES ($1, NULL, 'auto_cancel_order', 'order', $2,
                     '{\"status\":\"pending\"}'::jsonb,
                     '{\"status\":\"cancelled\",\"reason\":\"unpaid_30min\"}'::jsonb,
                     NOW())",
        )
        .bind(Uuid::new_v4())
        .bind(order_id.to_string())
        .execute(pool)
        .await;
    }

    Ok(rows.len())
}
