/// POST /api/v1/admin/orders/{id}/status
async fn admin_update_order_status(
    pool: web::Data<DbPool>,
    auth: AuthContext,
    path: web::Path<Uuid>,
    body: web::Json<UpdateOrderStatusBody>,
) -> Result<HttpResponse, AppError> {
    auth.require_role("Administrator")?;
    let order_id = path.into_inner();

    let valid_statuses = ["pending", "confirmed", "fulfilled", "cancelled", "refunded"];
    if !valid_statuses.contains(&body.status.as_str()) {
        return Err(AppError::ValidationError(format!(
            "Invalid status '{}'. Must be one of: {}",
            body.status,
            valid_statuses.join(", ")
        )));
    }

    // Load current status.
    let (current_status, user_id): (String, Uuid) = sqlx::query_as(
        "SELECT status, user_id FROM orders WHERE id = $1",
    )
    .bind(order_id)
    .fetch_optional(pool.get_ref())
    .await?
    .ok_or_else(|| AppError::NotFound(format!("Order {} not found.", order_id)))?;

    if current_status == body.status {
        return Err(AppError::ConflictError(format!(
            "Order is already '{}'.",
            body.status
        )));
    }

    // Disallow moving out of terminal states.
    if matches!(current_status.as_str(), "cancelled" | "refunded") {
        return Err(AppError::ConflictError(format!(
            "Cannot change status of a '{}' order.",
            current_status
        )));
    }

    let fulfilled_fields = if body.status == "fulfilled" {
        "fulfilled_at = NOW(), fulfilled_by = $3,"
    } else {
        ""
    };

    sqlx::query(&format!(
        "UPDATE orders SET status = $1, updated_at = NOW(), {} notes = COALESCE($2, notes)
         WHERE id = $4",
        if !fulfilled_fields.is_empty() {
            format!("{} fulfilled_by = $3,", "fulfilled_at = NOW(),")
        } else {
            String::new()
        }
    ))
    .bind(&body.status)
    .bind(&body.notes)
    .bind(auth.0.user_id)
    .bind(order_id)
    .execute(pool.get_ref())
    .await
    .map_err(|_| {
        // Fall back to simpler query without fulfilled_at if the above fails.
        AppError::InternalError("Status update failed.".into())
    })?;

    // Simpler, always-safe update.
    sqlx::query(
        "UPDATE orders SET status = $1, updated_at = NOW(),
         fulfilled_at = CASE WHEN $1 = 'fulfilled' THEN NOW() ELSE fulfilled_at END,
         fulfilled_by = CASE WHEN $1 = 'fulfilled' THEN $2 ELSE fulfilled_by END
         WHERE id = $3",
    )
    .bind(&body.status)
    .bind(auth.0.user_id)
    .bind(order_id)
    .execute(pool.get_ref())
    .await?;

    // Customer notification.
    let subject = format!("Order {} status update", &order_id.to_string()[..8]);
    let notif_body = format!(
        "Your order status has been updated to: {}.",
        body.status
    );
    let _ = sqlx::query(
        "INSERT INTO notifications
             (id, recipient_id, subject, body, notification_type, created_at)
         VALUES ($1, $2, $3, $4, 'order', NOW())",
    )
    .bind(Uuid::new_v4())
    .bind(user_id)
    .bind(&subject)
    .bind(&notif_body)
    .execute(pool.get_ref())
    .await;

    log_audit(
        pool.get_ref(),
        auth.0.user_id,
        "update_order_status",
        "order",
        &order_id.to_string(),
        Some(serde_json::json!({ "status": current_status })),
        Some(serde_json::json!({ "status": body.status })),
    )
    .await?;

    Ok(HttpResponse::Ok().json(serde_json::json!({
        "order_id": order_id,
        "old_status": current_status,
        "new_status": body.status,
        "message": "Order status updated."
    })))
}

