#[derive(Serialize)]
struct KpiResponse {
    /// Sum of total_cents for confirmed + fulfilled orders created today (UTC).
    daily_sales_cents: i64,
    /// Average total_cents for confirmed + fulfilled orders in last 30 days.
    average_order_value_cents: i64,
