    assert_eq!(cancelled[0].0, order_id);

    // Verify.
    let status: String = sqlx::query_scalar("SELECT status FROM orders WHERE id = $1")
        .bind(order_id)
        .fetch_one(&pool)
        .await
        .expect("query failed");

    assert_eq!(status, "cancelled");

    // Clean up.
    sqlx::query("DELETE FROM orders WHERE id = $1")
        .bind(order_id)
        .execute(&pool)
        .await
        .ok();
}

