                        placeholder="apparel"
                    />
                </div>
                <div class="form-row">
                    <label>{ "Initial Stock" }</label>
                    <input
                        type="number"
                        min="0"
                        value={(*new_qty).clone()}
                        oninput={
                            let s = new_qty.clone();
                            Callback::from(move |e: InputEvent| {
                                let el: HtmlInputElement = e.target_unchecked_into();
                                s.set(el.value());
                            })
                        }
                        placeholder="0"
                    />
                </div>
                <button
                    class="btn btn-primary"
                    onclick={on_create}
                    disabled={*creating}
                >
                    if *creating { { "Creating\u{2026}" } } else { { "Create Product" } }
                </button>
            </div>

            // ── Product table ─────────────────────────────────────────────
            if *loading {
                <p>{ "Loading\u{2026}" }</p>
            } else {
                <table class="data-table">
                    <thead>
                        <tr>
                            <th>{ "Name" }</th>
                            <th>{ "SKU" }</th>
                            <th>{ "Category" }</th>
                            <th>{ "Price" }</th>
                            <th>{ "Stock" }</th>
                            <th>{ "Active" }</th>
                            <th>{ "Actions" }</th>
                        </tr>
                    </thead>
                    <tbody>
                        { products.iter().map(|p| {
                            let p = p.clone();
                            let token = state.token.clone().unwrap_or_default();
                            let error2 = error.clone();
                            let success2 = success.clone();
                            let reload2 = reload.clone();

                            let on_deactivate = {
                                let p = p.clone();
                                let token = token.clone();
                                let error2 = error2.clone();
                                let success2 = success2.clone();
                                let reload2 = reload2.clone();
                                Callback::from(move |_: MouseEvent| {
                                    let pid = p.id;
                                    let pname = p.name.clone();
                                    let token = token.clone();
                                    let error2 = error2.clone();
                                    let success2 = success2.clone();
                                    let reload2 = reload2.clone();
                                    spawn_local(async move {
                                        match store::admin_deactivate_product(&token, &pid).await {
                                            Ok(_) => {
                                                success2.set(format!("'{}' deactivated.", pname));
                                                reload2.emit(());
                                            }
                                            Err(e) => {
                                                error2.set(format!("Deactivate failed: {}", e));
                                            }
                                        }
                                    });
                                })
                            };

                            let stock_display = match p.quantity {
                                Some(q) if q < p.low_stock_threshold.unwrap_or(10) && q > 0 =>
                                    format!("{} ⚠", q),
                                Some(q) => q.to_string(),
                                None => "—".to_string(),
                            };

                            html! {
                                <tr key={p.id.to_string()}>
                                    <td>{ &p.name }</td>
                                    <td>{ p.sku.as_deref().unwrap_or("—") }</td>
                                    <td>{ p.category.as_deref().unwrap_or("—") }</td>
                                    <td>{ p.price_display() }</td>
                                    <td>{ stock_display }</td>
                                    <td>{ if p.active { "Yes" } else { "No" } }</td>
                                    <td>
                                        if p.active {
                                            <button
                                                class="btn-sm btn-danger"
                                                onclick={on_deactivate}
                                            >
                                                { "Deactivate" }
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        }).collect::<Html>() }
                    </tbody>
                </table>
            }
        </div>
    }
}
"}

