1	use actix_cors::Cors;
2	use actix_web::{middleware::Logger, web, App, HttpServer};
3	use dotenv::dotenv;
4	use log::info;
5	
6	mod config;
7	mod db;
8	mod errors;
9	mod middleware;
10	mod models;
11	mod routes;
12	mod services;
13	
14	#[actix_web::main]
15	async fn main() -> std::io::Result<()> {
16	    dotenv().ok();
17	
18	    let cfg = config::Config::from_env();
19	
20	    env_logger::Builder::from_env(
21	        env_logger::Env::default().default_filter_or(&cfg.log_level),
22	    )
23	    .init();
24	
25	    info!("Meridian backend starting on {}:{}", cfg.host, cfg.port);
26	
27	    let pool = db::create_pool(&cfg.database_url)
28	        .await
29	        .expect("Failed to create database pool");
30	
31	    info!("Database pool created");
32	
33	    // Run migrations on startup
34	    db::run_migrations(&pool)
35	        .await
36	        .expect("Failed to run database migrations");
37	
38	    info!("Migrations applied successfully");
39	
40	    // Spawn background scheduler (auto-close unpaid orders after 30 min)
41	    let scheduler_pool = pool.clone();
42	    tokio::spawn(async move {
43	        services::scheduler::run_scheduler(scheduler_pool).await;
44	    });
45	    info!("Background scheduler started");
46	
47	    let pool = web::Data::new(pool);
48	    let bind_addr = format!("{}:{}", cfg.host, cfg.port);
49	
50	    info!("Starting HTTP server at http://{}", bind_addr);
51	
52	    HttpServer::new(move || {
53	        let cors = Cors::default()
54	            .allowed_origin("http://localhost:8081")
55	            .allowed_origin("http://127.0.0.1:8081")
56	            .allow_any_method()
57	            .allow_any_header()
58	            .supports_credentials()
59	            .max_age(3600);
60	
61	        App::new()
62	            .app_data(pool.clone())
63	            .wrap(cors)
64	            .wrap(Logger::default())
65	            .configure(routes::configure_routes)
66	    })
67	    .bind(&bind_addr)?
68	    .run()
69	    .await
70	}
71	

