2	use std::env;
3	
4	#[derive(Debug, Clone)]
5	pub struct Config {
6	    pub database_url: String,
7	    pub host: String,
8	    pub port: u16,
9	    pub session_secret: String,
10	    pub session_max_age_seconds: i64,
11	    pub log_level: String,
12	}
13	
14	impl Config {
15	    pub fn from_env() -> Self {
16	        dotenv().ok();
17	
18	        let database_url = env::var("DATABASE_URL").unwrap_or_else(|_| {
19	            panic!("DATABASE_URL environment variable is required but not set. Please set it to your PostgreSQL connection string, e.g. postgres://user:password@localhost/meridian");
20	        });
21	
22	        let host = env::var("HOST").unwrap_or_else(|_| "127.0.0.1".to_string());
23	
24	        let port = env::var("PORT")
25	            .unwrap_or_else(|_| "8080".to_string())
26	            .parse::<u16>()
27	            .unwrap_or_else(|_| panic!("PORT must be a valid u16 integer"));
28	
29	        let session_secret = env::var("SESSION_SECRET").unwrap_or_else(|_| {
30	            panic!("SESSION_SECRET environment variable is required but not set. It must be at least 64 characters long.");
31	        });
32	
33	        if session_secret.len() < 64 {
34	            panic!(
35	                "SESSION_SECRET is too short ({} chars). It must be at least 64 characters long for security.",
36	                session_secret.len()
37	            );
38	        }
39	
40	        let session_max_age_seconds = env::var("SESSION_MAX_AGE_SECONDS")
41	            .unwrap_or_else(|_| "3600".to_string())
42	            .parse::<i64>()
43	            .unwrap_or_else(|_| panic!("SESSION_MAX_AGE_SECONDS must be a valid i64 integer"));
44	
45	        let log_level = env::var("LOG_LEVEL").unwrap_or_else(|_| "info".to_string());
46	
47	        Config {
48	            database_url,
49	            host,
50	            port,
51	            session_secret,
52	            session_max_age_seconds,
53	            log_level,
54	        }
55	    }
56	}
