        let admin_roles = vec!["Administrator".to_string()];
        let student_roles = vec!["Student".to_string()];
        let check = |roles: &Vec<String>| roles.iter().any(|r| r == "Administrator");
        assert!(check(&admin_roles));
        assert!(!check(&student_roles));
    }
}
"}

