impl LogQuery {
    fn effective_limit(&self) -> i64 {
        self.limit.unwrap_or(100).min(500).max(1)
    }

    fn effective_offset(&self) -> i64 {
        self.offset.unwrap_or(0).max(0)
    }

    fn since_ts(&self) -> Result<Option<DateTime<Utc>>, AppError> {
        self.since
            .as_deref()
            .map(|s| {
