                    .map(|d| d.and_hms_opt(23, 59, 59).unwrap().and_utc())
                    .map_err(|_| {
                        AppError::ValidationError(format!(
                            "Invalid 'until' date '{}'. Expected YYYY-MM-DD.",
                            s
