        Ok(result) => {
            // Update metadata with actual filename/path from the service.
            sqlx::query(
                "UPDATE backup_metadata
                 SET filename = $1, size_bytes = $2, checksum = $3,
                     status = 'completed', completed_at = NOW()
                 WHERE id = $4",
